code = """import json
import os

# Load the full articles dataset
articles = []

# Try to find and load the articles file
possible_keys = [key for key in locals().keys() if 'query_db' in str(key) or 'article' in str(key).lower()]

print('Checking variables:', possible_keys[:10])

# Look for the actual file path
file_path = None
for key, value in locals().items():
    if isinstance(value, str) and ('/tmp/' in value or 'output' in value) and '.json' in value:
        if os.path.exists(value):
            file_path = value
            print('Found file path:', file_path)
            break

if file_path:
    with open(file_path, 'r') as f:
        articles = json.load(f)
    print('Loaded articles from file:', len(articles))
else:
    # Try direct access to the variable storage
    articles_data = locals().get('var_functions.query_db:36', [])
    if articles_data and isinstance(articles_data, list):
        articles = articles_data
        print('Got articles from variable, count:', len(articles))

# Sports keywords
sports_keywords = [
    'football', 'soccer', 'basketball', 'baseball', 'tennis', 'golf', 
    'cricket', 'hockey', 'rugby', 'athlete', 'olympic',
    'nba', 'nfl', 'mlb', 'nhl', 'premier league', 'world cup',
    'stadium', 'arena', 'championship', 'tournament', 'match',
    'medal', 'coach', 'player', 'team', 'game', 'sports'
]

# Check each article
sports_articles = []
max_length = 0
longest_title = None

for article in articles:
    title = article.get('title', '').lower()
    desc = article.get('description', '').lower()
    full_text = title + ' ' + desc
    
    is_sports = any(keyword in full_text for keyword in sports_keywords)
    
    if is_sports:
        desc_len = len(article.get('description', ''))
        sports_articles.append({'title': article.get('title'), 'length': desc_len})
        
        if desc_len > max_length:
            max_length = desc_len
            longest_title = article.get('title')

print('Total articles:', len(articles))
print('Sports articles:', len(sports_articles))

if sports_articles:
    print('Longest sports description length:', max_length)
    print('Title:', longest_title)
else:
    print('No sports articles found')
    # Show longest overall for context
    sorted_articles = sorted(articles, key=lambda x: len(x.get('description', '')), reverse=True)
    if sorted_articles:
        print('Longest article overall:')
        print('Title:', sorted_articles[0].get('title'))
        print('Description length:', len(sorted_articles[0].get('description', '')))

result = {
    'sports_article_count': len(sports_articles),
    'title_with_longest_description': longest_title,
    'description_length': max_length
}

print('__RESULT__:')
print(json.dumps(result))"""

